// Get the JSON data from the input
const jsonData = $input.first().json.body.results

// Initialize count variable
let count = 0;

// Check if the data exists and count appropriately
if (jsonData) {
  if (Array.isArray(jsonData)) {
    // If it's an array, count the elements
    count = jsonData.length;
  } else if (typeof jsonData === 'object') {
    // If it's an object, count the properties
    count = Object.keys(jsonData).length;
  } else {
    // If it's a primitive value, count is 1
    count = 1;
  }
} else {
  // If data is null/undefined, count is 0
  count = 0;
}

// Return the count - n8n expects the return value to be an array of objects
return [{ json: { count: count, total_items: count } }];

// Alternative: If you want to also pass through the original data with the count
// return [{ json: { count: count, total_items: count, original_data: jsonData } }];
